export const extractCustomerId = (data) => {
  const candidates = [
    data?.cid,
    data?._id,
    data?.id,
    data?.userId,
    data?.customerId,
    data?.data?.cid,
    data?.data?._id,
    data?.data?.id,
    data?.data?.userId,
    data?.data?.customerId,
    data?.user?.cid,
    data?.user?._id,
    data?.user?.id,
    data?.customer?.cid,
    data?.customer?._id,
    data?.customer?.id,
    data?.enduser?.cid,
    data?.enduser?._id,
    data?.enduser?.id,
  ];

  return candidates.find(Boolean) || null;
};

export const getLoggedInCid = () => {
  if (typeof window === "undefined") return null;

  const savedCid = localStorage.getItem("cid");
  if (savedCid) return savedCid;

  try {
    const user = JSON.parse(localStorage.getItem("user") || "null");
    return extractCustomerId(user);
  } catch {
    return null;
  }
};

export const saveCustomerSession = (data) => {
  if (typeof window === "undefined") return null;

  localStorage.setItem("user", JSON.stringify(data));

  const token = data?.token || data?.data?.token || data?.user?.token;
  if (token) localStorage.setItem("userToken", token);

  const cid = extractCustomerId(data);
  if (cid) {
    localStorage.setItem("cid", cid);
    localStorage.setItem("userId", cid);
  }

  return cid;
};
